import { z } from "zod";

export const sanitizeRequestSchema = z.object({
  prompt: z.string().min(1).max(50000),
  strict: z.boolean().optional().default(false),
});

export const detectedThreatSchema = z.object({
  type: z.string(),
  pattern: z.string(),
  confidence: z.number().min(0).max(1),
  span: z
    .object({
      start: z.number(),
      end: z.number(),
    })
    .optional(),
});

export const sanitizeResponseSchema = z.object({
  clean: z.boolean(),
  sanitized: z.string(),
  threatScore: z.number().min(0).max(1),
  threats: z.array(detectedThreatSchema),
});

export type SanitizeRequest = z.infer<typeof sanitizeRequestSchema>;
export type SanitizeResponse = z.infer<typeof sanitizeResponseSchema>;
